function i(t,n){if(n<1)return{gratuityAmount:0,basicSalary:t,yearsOfService:n};const o=t/30;let u=0;n<=5?u=o*21*n:u=o*21*5+o*30*(n-5);const A=t*24;return u=Math.min(u,A),{gratuityAmount:u,basicSalary:t,yearsOfService:n}}function m(t,n,o=!1){if(o){const A=t/(1+n/100),c=t-A;return{netAmount:A,vatAmount:c,totalAmount:t}}const u=t*(n/100);return{netAmount:t,vatAmount:u,totalAmount:t+u}}export{m as c,i as u};
